# Standardization
# -----------------------------------------------------------------------------

def extract_pax_count(value: object) -> int:
    if value is None or (isinstance(value, float) and np.isnan(value)):
        return 0
    s = str(value).split("(")[0]
    nums = [int(x) for x in re.findall(r"\d+", s)]
    return int(sum(nums)) if nums else 0


def standardize_departure(df: pd.DataFrame) -> pd.DataFrame:
    df = df.copy().dropna(axis=1, how="all")
    rename = {}
    unnamed_count = 0
    for col in df.columns:
        n = normalize_text(col)
        if n in {"A/L", "AL", "AIRLINE"}:
            rename[col] = "airline"
        elif n == "IN":
            rename[col] = "in_flight"
        elif n == "OUT":
            rename[col] = "out_flight"
        elif n == "STA":
            rename[col] = "sta"
        elif n == "STD":
            rename[col] = "std"
        elif n == "FROM":
            rename[col] = "from"
        elif n == "TO":
            rename[col] = "to"
        elif "A/C" in n or "TYPE" in n:
            rename[col] = "ac_type"
        elif "EKIP" in n:
            rename[col] = "existing_team"
        elif "NOT" in n:
            rename[col] = "notes"
        elif "TRN" in n:
            rename[col] = "trn"
        elif "UNNAMED" in n or n == "":
            unnamed_count += 1
            if unnamed_count == 1:
                rename[col] = "day"
            else:
                rename[col] = f"extra_{unnamed_count}"
        else:
            rename[col] = normalize_text(col).lower().replace(" ", "_")
    df = df.rename(columns=rename)
    for required in ["day", "airline", "in_flight", "out_flight", "sta", "std", "from", "to", "ac_type", "existing_team", "notes"]:
        if required not in df.columns:
            df[required] = ""

    # Detect passenger column among extra columns.
    pax_col = None
    for c in df.columns:
        if c.startswith("extra"):
            s = df[c].dropna().astype(str)
            if not s.empty and s.str.contains(r"\d", regex=True).mean() > 0.25:
                pax_col = c
                break
    df["pax_raw"] = df[pax_col] if pax_col else ""
    df["day"] = df["day"].ffill().fillna("")
    df["airline"] = df["airline"].apply(lambda x: normalize_text(x).replace(" ", ""))
    df["std"] = pd.to_datetime(df["std"], dayfirst=True, errors="coerce")
    df["sta"] = pd.to_datetime(df["sta"], dayfirst=True, errors="coerce")
    df["pax_count"] = df["pax_raw"].apply(extract_pax_count)
    df["flight_id"] = (
        df["airline"].astype(str) + " | " + df["out_flight"].astype(str) + " | " + df["std"].dt.strftime("%d.%m %H:%M").fillna("")
    )
    df = df[(df["airline"] != "") & df["std"].notna()].copy()
    keep = ["flight_id", "day", "airline", "in_flight", "out_flight", "sta", "std", "from", "to", "ac_type", "pax_raw", "pax_count", "existing_team", "notes"]
    return df[keep].reset_index(drop=True)


def standardize_qualifications(df: pd.DataFrame) -> pd.DataFrame:
    df = df.copy().dropna(axis=1, how="all")
    lookup = {normalize_text(c): c for c in df.columns}
    ad_col = lookup.get("AD") or lookup.get("NAME") or df.columns[0]
    soyad_col = lookup.get("SOYAD") or lookup.get("SURNAME") or df.columns[1]
    q_col = lookup.get("QUALIFICATIONS") or lookup.get("QUALIFICATION") or df.columns[-1]
    out = pd.DataFrame({
        "name": [clean_name(a, b) for a, b in zip(df[ad_col], df[soyad_col])],
        "flight_qualifications": df[q_col].fillna(""),
    })
    out["name_key"] = out["name"].apply(normalize_text)
    out = out[out["name_key"] != ""].drop_duplicates("name_key", keep="last")
    return out.reset_index(drop=True)


def standardize_staff_and_shifts(week_df: pd.DataFrame, break_threshold: float, break_hours: float) -> Tuple[pd.DataFrame, pd.DataFrame, List[pd.Timestamp]]:
    df = week_df.copy().dropna(how="all").dropna(axis=1, how="all")
    lookup = {normalize_text(c): c for c in df.columns}
    for need in ["MAIL", "FULL/PART", "CINSIYET", "AD", "SOYAD", "GUZERGAH", "QUALIFICATIONS"]:
        if need not in lookup:
            df[need] = ""
            lookup[need] = need

    def classify_type(x: object) -> str:
        raw = normalize_text(x)
        num = safe_float(x, np.nan)
        if "PART" in raw or raw == "PT" or (not np.isnan(num) and num <= 25):
            return "PART"
        return "FULL"

    def base_role(x: object) -> str:
        raw = normalize_text(x)
        if "LA" in raw or "LIDER" in raw:
            return "LA"
        if "SEF" in raw or "ŞEF" in str(x).upper() or "SUP" in raw or "SPV" in raw:
            return "Supervisor"
        return "Agent"

    staff = pd.DataFrame({
        "email": df[lookup["MAIL"]].fillna(""),
        "work_type_raw": df[lookup["FULL/PART"]],
        "work_type": df[lookup["FULL/PART"]].apply(classify_type),
        "gender": df[lookup["CINSIYET"]].fillna(""),
        "first_name": df[lookup["AD"]].fillna(""),
        "last_name": df[lookup["SOYAD"]].fillna(""),
        "route": df[lookup["GUZERGAH"]].fillna(""),
        "base_qualification": df[lookup["QUALIFICATIONS"]].fillna(""),
    })
    staff["name"] = [clean_name(a, b) for a, b in zip(staff["first_name"], staff["last_name"])]
    staff["name_key"] = staff["name"].apply(normalize_text)
    staff["route"] = staff["route"].apply(lambda x: normalize_text(x).replace(" ", ""))
    staff["base_role"] = staff["base_qualification"].apply(base_role)
    staff["role_override"] = staff["base_role"]
    staff["active"] = True
    staff = staff[staff["name_key"] != ""].drop_duplicates("name_key", keep="first").reset_index(drop=True)
    staff["staff_id"] = staff.index.astype(str)

    id_by_key = dict(zip(staff["name_key"], staff["staff_id"]))
    cols = list(df.columns)
    date_cols: List[Tuple[object, object, pd.Timestamp]] = []
    for idx, col in enumerate(cols):
        parsed = parse_header_date(col)
        if parsed is not None:
            hour_col = cols[idx + 1] if idx + 1 < len(cols) else None
            date_cols.append((col, hour_col, parsed))

    rows = []
    for _, row in df.iterrows():
        name = clean_name(row.get(lookup["AD"], ""), row.get(lookup["SOYAD"], ""))
        key = normalize_text(name)
        staff_id = id_by_key.get(key)
        if not staff_id:
            continue
        for shift_col, hour_col, day_ts in date_cols:
            shift_txt = row.get(shift_col, "")
            raw_hours = row.get(hour_col, np.nan) if hour_col is not None else np.nan
            status = shift_status(shift_txt)
            start_dt, end_dt = parse_shift_interval(shift_txt, day_ts)
            rows.append({
                "staff_id": staff_id,
                "name": name,
                "name_key": key,
                "date": day_ts.date(),
                "shift_text": "" if pd.isna(shift_txt) else str(shift_txt),
                "status": status,
                "start_dt": start_dt,
                "end_dt": end_dt,
                "start_service": format_hhmm(start_dt.time()) if start_dt else "",
                "end_service": format_hhmm(end_dt.time()) if end_dt else "",
                "service_ok": service_ok(start_dt, end_dt) if status == STATUS_WORK else True,
                "raw_hours_from_file": safe_float(raw_hours, 0.0),
                "planned_work_hours": round(hours_between(start_dt, end_dt, break_threshold, break_hours), 2) if status == STATUS_WORK else 0.0,
            })
    return staff, pd.DataFrame(rows), [d for _, _, d in date_cols]


def merge_staff_qualifications(staff: pd.DataFrame, quals: pd.DataFrame) -> pd.DataFrame:
    if quals is None or quals.empty:
        staff = staff.copy()
        staff["flight_qualifications"] = ""
        return staff
    out = staff.merge(quals[["name_key", "flight_qualifications"]], on="name_key", how="left")
    out["flight_qualifications"] = out["flight_qualifications"].fillna("")
    return out


def standardize_hakedis(df: pd.DataFrame) -> pd.DataFrame:
    df = df.copy().dropna(axis=1, how="all")
    if df.empty:
        return pd.DataFrame(columns=["airline_rule", "criterion", "detail", "staff_text", "airline_rule_norm"])
    base = df.iloc[:, :4].copy()
    base.columns = ["airline_rule", "criterion", "detail", "staff_text"]
    base["airline_rule"] = base["airline_rule"].ffill()
    base["criterion"] = base["criterion"].ffill()
    base = base.dropna(how="all")
    base["airline_rule_norm"] = base["airline_rule"].apply(normalize_text)
    return base.reset_index(drop=True)

