def is_pool_aircraft(airline: object) -> bool:
    """Havuz uçakları: qualification aranmaz, herkes Agent olarak adaydır; ekipte en az 1 Supervisor gerekir."""
    code = normalize_text(airline).replace(" ", "")
    return code in {normalize_text(x).replace(" ", "") for x in POOL_AIRCRAFT_CODES}


def codes_for_rule_name(rule_name_norm: str) -> List[str]:
    codes: List[str] = []
    for key, vals in AIRLINE_RULE_NAME_TO_CODES.items():
        if key in rule_name_norm:
            codes.extend(vals)
    return list(dict.fromkeys(codes))


def parse_staff_text(staff_text: object, pax_count: int = 0) -> Tuple[int, int, str]:
    s = normalize_text(staff_text)
    if not s:
        return 3, 0, "Varsayılan 3 staff"
    m = re.search(r"HER\s+(\d+)\s+YOLCU", s)
    if m:
        divisor = int(m.group(1))
        return max(1, math.ceil(max(pax_count, 1) / divisor)), 0, f"Her {divisor} yolcu için 1 staff"
    la = 0
    m_la = re.search(r"(\d+)\s*LA", s)
    if m_la:
        la = int(m_la.group(1))
    plus = re.search(r"(\d+)\s*\+\s*(\d+)", s)
    if plus:
        return int(plus.group(1)) + int(plus.group(2)), la, str(staff_text)
    nums = [int(x) for x in re.findall(r"\d+", s)]
    if nums:
        return nums[0], la, str(staff_text)
    return 3, 0, str(staff_text)


def detail_matches(detail: object, criterion: object, pax_count: int, ac_type: object, std: pd.Timestamp) -> bool:
    d = normalize_text(detail)
    c = normalize_text(criterion)
    ac = normalize_text(ac_type)
    if not d:
        return True
    if "TIP" in c or "TIP" in d:
        nums = re.findall(r"\d+", d)
        if nums:
            return any(n in ac for n in nums)
    rng = re.search(r"(\d+)\s*[-–]\s*(\d+)", d)
    if rng:
        return int(rng.group(1)) <= pax_count <= int(rng.group(2))
    plus = re.search(r"(\d+)\s*\+", d)
    if plus:
        return pax_count >= int(plus.group(1))
    alt = re.search(r"(\d+)\s*ALTI", d)
    if alt:
        return pax_count < int(alt.group(1))
    if "GECE" in d:
        h = pd.Timestamp(std).hour
        return h >= 20 or h < 7
    if "GUNDUZ" in d:
        h = pd.Timestamp(std).hour
        return 7 <= h < 20
    return True


def estimate_required_staff_for_flight(flight: pd.Series, hakedis_rules: pd.DataFrame) -> Tuple[int, int, str]:
    airline = normalize_text(flight.get("airline", "")).replace(" ", "")
    pax = safe_int(flight.get("pax_count", 0), 0)
    if hakedis_rules is not None and not hakedis_rules.empty:
        rules = hakedis_rules.copy()
        rules["codes"] = rules["airline_rule_norm"].apply(codes_for_rule_name)
        matched = rules[rules["codes"].apply(lambda xs: airline in xs)]
        for _, r in matched.iterrows():
            if detail_matches(r.get("detail"), r.get("criterion"), pax, flight.get("ac_type", ""), flight.get("std")):
                total, la, reason = parse_staff_text(r.get("staff_text"), pax)
                return max(total, la), la, f"{r.get('airline_rule')} / {r.get('detail')} → {reason}"
    if pax > 0:
        total = min(10, max(2, math.ceil(pax / 60)))
        return total, 0, "Fallback: her ~60 yolcu için 1 staff"
    return 3, 0, "Fallback: yolcu yok, 3 staff"


def enrich_flights_with_requirements(flights: pd.DataFrame, hakedis: pd.DataFrame) -> pd.DataFrame:
    if flights.empty:
        return flights
    rows = []
    for _, f in flights.iterrows():
        total, la, reason = estimate_required_staff_for_flight(f, hakedis)
        pool_flag = is_pool_aircraft(f.get("airline", ""))
        if pool_flag:
            # Havuz uçakları için özel kural:
            # UZB, IAW, DAH, FAD, RAM, BRU, AWG uçaklarında qualification aranmaz.
            # Ekipte 1 adet herhangi Supervisor yeterlidir; LA zorunluluğu sıfırlanır.
            la = 0
            reason = f"HAVUZ UÇAK KURALI: herkes çıkabilir + 1 Supervisor yeterli. Hakediş hesabı: {reason}"
        rows.append({"required_total": int(total), "required_la": int(la), "required_reason": reason, "is_pool_aircraft": bool(pool_flag)})
    out = pd.concat([flights.reset_index(drop=True), pd.DataFrame(rows)], axis=1)
    out["manual_required_total"] = out["required_total"]
    out["manual_required_la"] = out["required_la"]
    out["require_supervisor"] = True
    return out


def build_alias_dict(alias_df: pd.DataFrame | None) -> Dict[str, List[str]]:
    aliases = {k: list(v) for k, v in DEFAULT_AIRLINE_ALIASES.items()}
    if alias_df is not None and not alias_df.empty:
        for _, row in alias_df.iterrows():
            code = normalize_text(row.get("A/L Kodu", "")).replace(" ", "")
            raw = row.get("Qualification Aliasları", "")
            if code:
                vals = [normalize_text(x) for x in re.split(r"[,;/|]+", str(raw)) if normalize_text(x)]
                if code not in vals:
                    vals.insert(0, code)
                aliases[code] = vals
    return aliases


def contains_alias(q: object, alias: str) -> bool:
    text = normalize_text(q)
    a = re.escape(normalize_text(alias))
    return bool(text and a and re.search(rf"(?<![A-Z0-9]){a}(?![A-Z0-9])", text))


def contains_role_marker(q: object, alias: str, marker: str) -> bool:
    text = normalize_text(q)
    a = re.escape(normalize_text(alias))
    m = re.escape(normalize_text(marker))
    if not text or not a:
        return False
    patterns = [
        rf"(?<![A-Z0-9]){m}\s*[-_/ ]\s*{a}(?![A-Z0-9])",
        rf"(?<![A-Z0-9]){a}\s*[-_/ ]\s*{m}(?![A-Z0-9])",
    ]
    return any(re.search(p, text) for p in patterns)


def roles_for_staff_airline(person: pd.Series, airline: str, aliases: Dict[str, List[str]]) -> List[str]:
    code = normalize_text(airline).replace(" ", "")
    base_role = person.get("role_override", person.get("base_role", "Agent"))

    # HAVUZ UÇAK KURALI
    # UZB, IAW, DAH, FAD, RAM, BRU, AWG uçaklarına qualification aranmadan herkes çıkabilir.
    # Normal Agent herkes olabilir; LA kişi LA olarak da görünebilir; Supervisor kişi Supervisor olarak seçilebilir.
    if is_pool_aircraft(code):
        roles: List[str] = ["Agent"]
        if base_role == "LA":
            roles.append("LA")
        if base_role == "Supervisor":
            roles.append("Supervisor")
        return list(dict.fromkeys(roles))

    q = person.get("flight_qualifications", "")
    alias_list = aliases.get(code, [code])
    has_plain = any(contains_alias(q, a) for a in alias_list)
    has_sup = any(contains_role_marker(q, a, "S") or contains_role_marker(q, a, "SPV") for a in alias_list)
    has_la = any(contains_role_marker(q, a, "L") or contains_role_marker(q, a, "LA") for a in alias_list)
    roles: List[str] = []
    if has_plain or has_sup or has_la:
        roles.append("Agent")
        if has_la or base_role == "LA":
            roles.append("LA")
        if has_sup or base_role == "Supervisor":
            roles.append("Supervisor")
    return list(dict.fromkeys(roles))

