def staff_hour_summary(staff: pd.DataFrame, shifts: pd.DataFrame) -> pd.DataFrame:
    if staff.empty:
        return pd.DataFrame()
    agg = pd.DataFrame(columns=["staff_id", "planned_work_hours", "file_hours", "work_days"])
    if not shifts.empty:
        agg = shifts.groupby("staff_id", as_index=False).agg(
            planned_work_hours=("planned_work_hours", "sum"),
            file_hours=("raw_hours_from_file", "sum"),
            work_days=("status", lambda x: int((x == STATUS_WORK).sum())),
        )
    out = staff.merge(agg, on="staff_id", how="left")
    for c in ["planned_work_hours", "file_hours", "work_days"]:
        out[c] = out[c].fillna(0)

    def status(row):
        if not bool(row.get("active", True)):
            return "Pasif"
        h = float(row.get("planned_work_hours", 0))
        if row.get("work_type") == "PART":
            return "OK" if h <= 25 else "Part max 25 aşıldı"
        if h < 40:
            return "Full min 40 altında"
        if h > 50:
            return "Full max 50 aşıldı"
        return "OK"

    out["limit_status"] = out.apply(status, axis=1)
    return out[["staff_id", "name", "work_type", "route", "role_override", "active", "planned_work_hours", "file_hours", "work_days", "limit_status"]]


def service_warnings(staff: pd.DataFrame, shifts: pd.DataFrame, valid_routes: Sequence[str]) -> pd.DataFrame:
    rows = []
    if shifts.empty:
        return pd.DataFrame(rows)
    route_map = staff.set_index("staff_id")["route"].to_dict()
    valid = set(valid_routes)
    for _, r in shifts.iterrows():
        if r.get("status") != STATUS_WORK:
            continue
        route = route_map.get(r.get("staff_id"), "")
        reasons = []
        if not bool(r.get("service_ok", False)):
            reasons.append(f"Vardiya {r.get('start_service')}-{r.get('end_service')} servis saatleriyle eşleşmiyor")
        if route and route not in valid:
            reasons.append(f"Güzergah listede yok: {route}")
        if reasons:
            rows.append({
                "Personel": r.get("name"), "Tarih": r.get("date"), "Vardiya": r.get("shift_text"), "Güzergah": route,
                "Geliş": r.get("start_service"), "Gidiş": r.get("end_service"), "Uyarı": " | ".join(reasons)
            })
    return pd.DataFrame(rows)


def rest_rule_violations(shifts: pd.DataFrame, min_rest: float) -> pd.DataFrame:
    rows = []
    if shifts.empty:
        return pd.DataFrame(rows)
    work = shifts[(shifts["status"] == STATUS_WORK) & shifts["start_dt"].notna() & shifts["end_dt"].notna()].copy()
    for _, grp in work.groupby("staff_id"):
        grp = grp.sort_values("start_dt")
        prev = None
        for _, row in grp.iterrows():
            if prev is not None:
                rest = (row["start_dt"] - prev["end_dt"]).total_seconds() / 3600
                if rest < min_rest:
                    rows.append({
                        "Personel": row["name"],
                        "Önceki Vardiya": f"{prev['start_dt']:%d.%m %H:%M}-{prev['end_dt']:%d.%m %H:%M}",
                        "Sonraki Vardiya": f"{row['start_dt']:%d.%m %H:%M}-{row['end_dt']:%d.%m %H:%M}",
                        "Dinlenme": round(rest, 2),
                        "Uyarı": f"{min_rest} saat kuralı ihlal",
                    })
            prev = row
    return pd.DataFrame(rows)


def normalize_request_table(req: pd.DataFrame) -> pd.DataFrame:
    if req is None or req.empty:
        return pd.DataFrame(columns=["name_key", "date", "type", "note"])
    out = req.copy()
    for c, default in [("Personel", ""), ("Tarih", date.today()), ("Tip", "DO Talebi"), ("Not", "")]:
        if c not in out.columns:
            out[c] = default
    out["name_key"] = out["Personel"].apply(normalize_text)
    out["date"] = pd.to_datetime(out["Tarih"], errors="coerce").dt.date
    out["type"] = out["Tip"].astype(str)
    out["note"] = out["Not"].astype(str)
    return out[out["name_key"] != ""][["name_key", "date", "type", "note"]]


def is_blocked(name_key: str, target_date: date, req_norm: pd.DataFrame) -> Tuple[bool, str]:
    if req_norm is None or req_norm.empty:
        return False, ""
    hit = req_norm[(req_norm["name_key"] == normalize_text(name_key)) & (req_norm["date"] == target_date)]
    if hit.empty:
        return False, ""
    return True, ", ".join(hit["type"].astype(str).unique())


def apply_staff_editor(base_staff: pd.DataFrame, edited: pd.DataFrame) -> pd.DataFrame:
    if edited is None or edited.empty:
        return base_staff.copy()
    base_by_key = {normalize_text(r["name"]): r for _, r in base_staff.iterrows()}
    rows = []
    for idx, r in edited.iterrows():
        name = clean_name(r.get("name", ""))
        if not name:
            continue
        key = normalize_text(name)
        if key in base_by_key:
            base = dict(base_by_key[key])
        else:
            base = {"staff_id": f"new_{idx}", "name": name, "name_key": key, "first_name": name.split(" ")[0], "last_name": " ".join(name.split(" ")[1:])}
        base.update({
            "name": name,
            "name_key": key,
            "email": r.get("email", base.get("email", "")),
            "work_type": r.get("work_type", base.get("work_type", "FULL")),
            "gender": r.get("gender", base.get("gender", "")),
            "route": normalize_text(r.get("route", base.get("route", ""))).replace(" ", ""),
            "base_role": r.get("base_role", base.get("base_role", "Agent")),
            "role_override": r.get("role_override", base.get("role_override", base.get("base_role", "Agent"))),
            "active": bool(r.get("active", True)),
            "flight_qualifications": r.get("flight_qualifications", base.get("flight_qualifications", "")),
        })
        rows.append(base)
    return pd.DataFrame(rows).reset_index(drop=True)


def candidate_rows_for_flight(
    flight: pd.Series,
    staff: pd.DataFrame,
    shifts: pd.DataFrame,
    req_norm: pd.DataFrame,
    aliases: Dict[str, List[str]],
    duty_start: datetime,
    duty_end: datetime,
    assigned_by_staff: Dict[str, List[Tuple[datetime, datetime, str]]],
    hmap: Dict[str, dict],
    allow_non_service: bool,
) -> List[dict]:
    target_date = duty_start.date()
    # Duty can start previous day for early flights; use shifts that actually cover the interval.
    possible = shifts[(shifts["status"] == STATUS_WORK) & shifts["start_dt"].notna() & shifts["end_dt"].notna()].copy()
    possible = possible[(possible["start_dt"] <= duty_start) & (possible["end_dt"] >= duty_end)]
    if not allow_non_service:
        possible = possible[possible["service_ok"] == True]
    if possible.empty:
        return []
    staff_by_id = {str(r["staff_id"]): r for _, r in staff.iterrows()}
    rows = []
    seen = set()
    for _, sh in possible.iterrows():
        sid = str(sh["staff_id"])
        if sid in seen:
            continue
        seen.add(sid)
        person = staff_by_id.get(sid)
        if person is None or not bool(person.get("active", True)):
            continue
        blocked, _ = is_blocked(person.get("name_key", ""), pd.Timestamp(flight["std"]).date(), req_norm)
        if blocked:
            continue
        roles = roles_for_staff_airline(person, flight["airline"], aliases)
        if not roles:
            continue
        limit_status = hmap.get(sid, {}).get("limit_status", "")
        if limit_status in {"Part max 25 aşıldı", "Full max 50 aşıldı", "Pasif"}:
            continue
        conflict = False
        for a_start, a_end, _fid in assigned_by_staff.get(sid, []):
            if overlap(duty_start, duty_end, a_start, a_end):
                conflict = True
                break
        if conflict:
            continue
        rows.append({
            "staff_id": sid,
            "Personel": person["name"],
            "_roles": roles,
            "Rol Yetkileri": ", ".join(roles),
            "Ana Rol": person.get("role_override", person.get("base_role", "Agent")),
            "Güzergah": person.get("route", ""),
            "Vardiya": sh.get("shift_text", ""),
            "Vardiya Başlangıç": sh.get("start_dt"),
            "Vardiya Bitiş": sh.get("end_dt"),
            "Haftalık Saat": hmap.get(sid, {}).get("planned_work_hours", 0.0),
            "Atama Sayısı": hmap.get(sid, {}).get("assignment_count", 0),
        })
    return rows


def choose(pool: List[dict], need: int, role: str, selected: set, assignment_counts: Dict[str, int]) -> List[dict]:
    if need <= 0:
        return []
    candidates = []
    for r in pool:
        if r["staff_id"] in selected:
            continue
        if role != "Any" and role not in r["_roles"]:
            continue
        rr = dict(r)
        rr["_assign_count"] = assignment_counts.get(r["staff_id"], 0)
        rr["_role_bonus"] = 0 if role == "Any" or rr.get("Ana Rol") == role else 1
        candidates.append(rr)
    candidates.sort(key=lambda x: (x["_assign_count"], x.get("Haftalık Saat", 0), x["_role_bonus"], x["Personel"]))
    return candidates[:need]


def generate_plan(
    flights: pd.DataFrame,
    staff: pd.DataFrame,
    shifts: pd.DataFrame,
    req_norm: pd.DataFrame,
    aliases: Dict[str, List[str]],
    duty_lead: int,
    duty_after: int,
    allow_non_service: bool,
    selected_dates: Sequence[date] | None = None,
) -> Tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    assignments, warnings, diagnostics = [], [], []
    if flights.empty or staff.empty or shifts.empty:
        return pd.DataFrame(assignments), pd.DataFrame(warnings), pd.DataFrame(diagnostics)
    hsum = staff_hour_summary(staff, shifts)
    hmap = hsum.set_index("staff_id").to_dict("index")
    assigned_by_staff: Dict[str, List[Tuple[datetime, datetime, str]]] = {}
    assignment_counts: Dict[str, int] = {}

    fdf = flights.copy()
    fdf["_date"] = pd.to_datetime(fdf["std"]).dt.date
    if selected_dates:
        allowed = set(selected_dates)
        fdf = fdf[fdf["_date"].isin(allowed)]
    fdf = fdf.sort_values("std")

    for _, flight in fdf.iterrows():
        std = pd.Timestamp(flight["std"]).to_pydatetime()
        duty_start = std - timedelta(minutes=int(duty_lead))
        duty_end = std + timedelta(minutes=int(duty_after))
        required_total = safe_int(flight.get("manual_required_total", flight.get("required_total", 3)), 3)
        required_la = safe_int(flight.get("manual_required_la", flight.get("required_la", 0)), 0)
        require_sup = bool(flight.get("require_supervisor", True))
        pool = candidate_rows_for_flight(flight, staff, shifts, req_norm, aliases, duty_start, duty_end, assigned_by_staff, hmap, allow_non_service)
        diagnostics.append({
            "Uçuş": flight["flight_id"], "STD": std, "Hakediş": required_total,
            "Havuz Uçak": "Evet" if is_pool_aircraft(flight["airline"]) else "Hayır",
            "Aday Sayısı": len(pool), "Supervisor Aday": sum(1 for r in pool if "Supervisor" in r["_roles"]),
            "LA Aday": sum(1 for r in pool if "LA" in r["_roles"]),
        })
        selected_rows: List[Tuple[dict, str]] = []
        selected_ids = set()
        if require_sup:
            for r in choose(pool, 1, "Supervisor", selected_ids, assignment_counts):
                selected_rows.append((r, "Supervisor")); selected_ids.add(r["staff_id"])
        for r in choose(pool, required_la, "LA", selected_ids, assignment_counts):
            selected_rows.append((r, "LA")); selected_ids.add(r["staff_id"])
        remain = max(0, required_total - len(selected_rows))
        for r in choose(pool, remain, "Any", selected_ids, assignment_counts):
            role = r["Ana Rol"] if r["Ana Rol"] in r["_roles"] else "Agent"
            selected_rows.append((r, role)); selected_ids.add(r["staff_id"])

        if len(selected_rows) < required_total:
            warnings.append({
                "Uçuş": flight["flight_id"], "STD": std, "Gereken": required_total, "Bulunan": len(selected_rows),
                "Uyarı": "Yeterli aday yok. Qualification, vardiya kapsaması, servis, DO/izin veya çakışma kontrol edilmeli.",
            })
        if require_sup and not any(role == "Supervisor" for _, role in selected_rows):
            warnings.append({"Uçuş": flight["flight_id"], "STD": std, "Gereken": "1 Supervisor", "Bulunan": 0, "Uyarı": "Supervisor bulunamadı."})
        if required_la > 0 and sum(1 for _, role in selected_rows if role == "LA") < required_la:
            warnings.append({"Uçuş": flight["flight_id"], "STD": std, "Gereken": required_la, "Bulunan": sum(1 for _, role in selected_rows if role == "LA"), "Uyarı": "LA eksik."})

        for idx, (r, duty_role) in enumerate(selected_rows, 1):
            assignments.append({
                "Uçuş ID": flight["flight_id"], "Gün": flight.get("day", ""), "A/L": flight["airline"],
                "IN": flight.get("in_flight", ""), "OUT": flight.get("out_flight", ""), "STD": std,
                "Görev Başlangıç": duty_start, "Görev Bitiş": duty_end, "Sıra": idx,
                "Personel": r["Personel"], "staff_id": r["staff_id"], "Görev Rolü": duty_role,
                "Güzergah": r["Güzergah"], "Vardiya": r["Vardiya"], "Haftalık Saat": r["Haftalık Saat"],
                "Hakediş": required_total, "Hakediş LA": required_la, "Hakediş Nedeni": flight.get("required_reason", ""),
                "Not": "Otomatik öneri - STD-3:10 hazır / STD+20 uygunluk kuralı",
            })
            assigned_by_staff.setdefault(r["staff_id"], []).append((duty_start, duty_end, flight["flight_id"]))
            assignment_counts[r["staff_id"]] = assignment_counts.get(r["staff_id"], 0) + 1
    return pd.DataFrame(assignments), pd.DataFrame(warnings), pd.DataFrame(diagnostics)


def validate_plan(plan: pd.DataFrame, flights: pd.DataFrame, staff: pd.DataFrame, shifts: pd.DataFrame, req_norm: pd.DataFrame, aliases: Dict[str, List[str]]) -> pd.DataFrame:
    rows = []
    if plan is None or plan.empty:
        return pd.DataFrame(rows)
    staff_by_name = {normalize_text(r["name"]): r for _, r in staff.iterrows()}
    flight_by_id = {str(r["flight_id"]): r for _, r in flights.iterrows()}
    slots = []
    for i, r in plan.iterrows():
        errors = []
        person = staff_by_name.get(normalize_text(r.get("Personel", "")))
        flight = flight_by_id.get(str(r.get("Uçuş ID", "")))
        if person is None:
            errors.append("Personel master listede yok")
        if flight is None:
            errors.append("Uçuş bulunamadı")
        if person is not None and flight is not None:
            duty_start = pd.to_datetime(r.get("Görev Başlangıç"), errors="coerce")
            duty_end = pd.to_datetime(r.get("Görev Bitiş"), errors="coerce")
            if pd.isna(duty_start) or pd.isna(duty_end):
                std = pd.Timestamp(flight["std"]).to_pydatetime()
                duty_start = std - timedelta(minutes=95)
                duty_end = std + timedelta(minutes=30)
            else:
                duty_start = duty_start.to_pydatetime(); duty_end = duty_end.to_pydatetime()
            roles = roles_for_staff_airline(person, flight["airline"], aliases)
            duty_role = r.get("Görev Rolü", "Agent")
            if duty_role not in roles and not (duty_role == "Agent" and roles):
                errors.append(f"{flight['airline']} için {duty_role} yetkisi görünmüyor")
            possible = shifts[(shifts["staff_id"].astype(str) == str(person["staff_id"])) & (shifts["status"] == STATUS_WORK)]
            possible = possible[(possible["start_dt"] <= duty_start) & (possible["end_dt"] >= duty_end)]
            if possible.empty:
                errors.append("Vardiya görev saatini kapsamıyor")
            elif not bool(possible.iloc[0].get("service_ok", False)):
                errors.append("Vardiya servis saatlerine uymuyor")
            blocked, reason = is_blocked(person["name_key"], pd.Timestamp(flight["std"]).date(), req_norm)
            if blocked:
                errors.append(f"DO/izin engeli: {reason}")
            for sid, s, e, fid in slots:
                if sid == person["staff_id"] and overlap(duty_start, duty_end, s, e):
                    errors.append(f"Başka görevle çakışıyor: {fid}")
            slots.append((person["staff_id"], duty_start, duty_end, r.get("Uçuş ID", "")))
        rows.append({"Satır": i + 1, "Uçuş": r.get("Uçuş ID", ""), "Personel": r.get("Personel", ""), "Durum": "OK" if not errors else "Uyarı", "Açıklama": " | ".join(errors) if errors else "Uygun"})

    # Uçuş bazlı ekip kontrolü: Supervisor şartı manuel değişikliklerden sonra da korunur.
    for fid, team in plan.groupby("Uçuş ID", dropna=False):
        flight = flight_by_id.get(str(fid))
        if flight is None:
            continue
        if bool(flight.get("require_supervisor", True)):
            has_sup = team["Görev Rolü"].astype(str).eq("Supervisor").any() if "Görev Rolü" in team.columns else False
            if not has_sup:
                note = "Havuz uçakta da en az 1 Supervisor zorunlu" if is_pool_aircraft(flight.get("airline", "")) else "Ekipte en az 1 Supervisor zorunlu"
                rows.append({"Satır": "Ekip", "Uçuş": fid, "Personel": "", "Durum": "Uyarı", "Açıklama": note})
    return pd.DataFrame(rows)


def delay_recommendations(
    selected_flight_id: str,
    delay_minutes: int,
    plan: pd.DataFrame,
    flights: pd.DataFrame,
    staff: pd.DataFrame,
    shifts: pd.DataFrame,
    req_norm: pd.DataFrame,
    aliases: Dict[str, List[str]],
    allow_non_service: bool,
    duty_after: int = AVAILABLE_AFTER_STD_DEFAULT,
) -> Tuple[pd.DataFrame, str]:
    """AI Smart Advisor: gecikme sonrası devir ihtiyacını ve en uygun adayları önerir.

    Normal kural: ekip STD + duty_after dakikada serbest kalır.
    Gecikme varsa ekip yeni STD + duty_after dakikaya kadar meşgul sayılır.
    Bu uzama, personelin servisini veya bir sonraki görevini bozuyorsa uygun devir adayı aranır.
    """
    if plan is None or plan.empty:
        return pd.DataFrame(), "Önce 6 Planlama sekmesinden plan oluşturmalısın."
    frow = flights[flights["flight_id"].astype(str) == str(selected_flight_id)]
    if frow.empty:
        return pd.DataFrame(), "Uçuş bulunamadı."
    flight = frow.iloc[0]
    old_std = pd.Timestamp(flight["std"]).to_pydatetime()
    new_std = old_std + timedelta(minutes=int(delay_minutes))
    extension_start = old_std + timedelta(minutes=int(duty_after))
    extension_end = new_std + timedelta(minutes=int(duty_after))
    if extension_end <= extension_start:
        return pd.DataFrame(), "Gecikme yok; devir gerekmiyor."

    team = plan[plan["Uçuş ID"].astype(str) == str(selected_flight_id)].copy()
    if team.empty:
        return pd.DataFrame(), "Bu uçuşun otomatik/manuel planında ekip görünmüyor."

    staff_by_name = {normalize_text(r["name"]): r for _, r in staff.iterrows()}
    existing_by_staff: Dict[str, List[Tuple[datetime, datetime, str]]] = {}
    for _, r in plan.iterrows():
        if str(r.get("Uçuş ID", "")) == str(selected_flight_id):
            continue
        person = staff_by_name.get(normalize_text(r.get("Personel", "")))
        if person is None:
            continue
        s = pd.to_datetime(r.get("Görev Başlangıç"), errors="coerce")
        e = pd.to_datetime(r.get("Görev Bitiş"), errors="coerce")
        if not pd.isna(s) and not pd.isna(e):
            existing_by_staff.setdefault(str(person["staff_id"]), []).append((s.to_pydatetime(), e.to_pydatetime(), str(r.get("Uçuş ID", ""))))

    hsum = staff_hour_summary(staff, shifts)
    hmap = hsum.set_index("staff_id").to_dict("index") if not hsum.empty else {}
    # Devir adayı sadece gecikmenin uzama aralığını karşılayabilirse seçilir.
    pool = candidate_rows_for_flight(flight, staff, shifts, req_norm, aliases, extension_start, extension_end, existing_by_staff, hmap, allow_non_service)

    rows = []
    for _, member in team.iterrows():
        person = staff_by_name.get(normalize_text(member.get("Personel", "")))
        if person is None:
            continue
        sid = str(person["staff_id"])
        shift_cover = shifts[(shifts["staff_id"].astype(str) == sid) & (shifts["status"] == STATUS_WORK)]
        shift_cover = shift_cover[(shift_cover["start_dt"] <= extension_start) & (shift_cover["end_dt"] >= extension_end)]
        conflict_items = [(s, e, fid) for s, e, fid in existing_by_staff.get(sid, []) if overlap(extension_start, extension_end, s, e)]

        problems = []
        if shift_cover.empty:
            problems.append("Gecikmeli bitiş vardiya/servis çıkışını aşıyor")
        else:
            end_service = format_hhmm(pd.Timestamp(shift_cover.iloc[0]["end_dt"]).time())
            if end_service not in DEPARTURE_SERVICES:
                problems.append("Gecikmeli bitiş gidiş servisiyle uyumsuz")
        if conflict_items:
            problems.append("Sonraki görevle çakışıyor: " + ", ".join(x[2] for x in conflict_items[:3]))

        if not problems:
            rows.append({
                "Etkilenen Personel": member.get("Personel"),
                "Mevcut Rol": member.get("Görev Rolü"),
                "Sorun": "Sorun görünmüyor",
                "Önerilen Devir": "Gerek yok",
                "AI Öneri Notu": "Kendi vardiyası ve servis çıkışı gecikmeli bitişi karşılıyor.",
            })
            continue

        role_needed = member.get("Görev Rolü", "Agent")
        candidates = [p for p in pool if p["staff_id"] != sid]
        if role_needed in {"Supervisor", "LA"}:
            role_candidates = [p for p in candidates if role_needed in p["_roles"]]
            if role_candidates:
                candidates = role_candidates
        candidates.sort(key=lambda x: (
            0 if x.get("Güzergah") == person.get("route") else 1,
            x.get("Haftalık Saat", 0),
            x.get("Atama Sayısı", 0),
            x.get("Personel", ""),
        ))
        if not candidates:
            rows.append({
                "Etkilenen Personel": member.get("Personel"),
                "Mevcut Rol": role_needed,
                "Sorun": " | ".join(problems),
                "Önerilen Devir": "Uygun aday yok",
                "AI Öneri Notu": "Aynı yetki + vardiya + servis + çakışma kurallarında aday bulunamadı. Manuel kontrol gerekir.",
            })
        else:
            b = candidates[0]
            rows.append({
                "Etkilenen Personel": member.get("Personel"),
                "Mevcut Rol": role_needed,
                "Sorun": " | ".join(problems),
                "Önerilen Devir": b["Personel"],
                "Önerilen Güzergah": b["Güzergah"],
                "Önerilen Vardiya": b["Vardiya"],
                "AI Öneri Notu": f"{extension_start:%H:%M}-{extension_end:%H:%M} gecikme uzamasını devralabilir. Yetki: {b['Rol Yetkileri']}. Öncelik: aynı güzergah, düşük saat, düşük atama.",
            })
    summary = f"{flight['out_flight']} için STD {old_std:%d.%m.%Y %H:%M} → gecikmeli STD {new_std:%d.%m.%Y %H:%M}. Normal serbest kalış {extension_start:%H:%M}, gecikmeli serbest kalış {extension_end:%H:%M}."
    return pd.DataFrame(rows), summary

