# Data loading
# -----------------------------------------------------------------------------

def get_source(uploaded, default_key: str):
    if uploaded is not None:
        return uploaded
    path = DEFAULT_FILES[default_key]
    return path if Path(path).exists() else None


def load_all_data(upload_departure, upload_qual, upload_week, upload_hakedis, break_threshold: float, break_hours: float):
    sources = {
        "departure": get_source(upload_departure, "departure"),
        "qualification": get_source(upload_qual, "qualification"),
        "week": get_source(upload_week, "week"),
        "hakedis": get_source(upload_hakedis, "hakedis"),
    }
    missing = [k for k, v in sources.items() if not source_exists(v)]
    if missing:
        return None, None, None, None, None, [], "", f"Eksik dosya: {', '.join(missing)}. Lütfen sol menüden yükle."

    # If separate departure CSV is poor, the app still allows it; if no separate file, week workbook's departure sheet could be used.
    dep_src = sources["departure"]
    dep_name = getattr(dep_src, "name", str(dep_src)).lower()
    if dep_name.endswith(".csv"):
        dep_raw = read_csv_smart(dep_src)
    else:
        dep_raw = read_excel_sheet(dep_src, preferred_names=["20.HAFTA DEPARTURE", "DEPARTURE"])
    flights = standardize_departure(dep_raw)

    q_src = sources["qualification"]
    q_name = getattr(q_src, "name", str(q_src)).lower()
    if q_name.endswith(".csv"):
        q_raw = read_csv_smart(q_src)
    else:
        q_raw = read_excel_sheet(q_src, required_cols=["AD", "SOYAD", "QUALIFICATIONS"])
    quals = standardize_qualifications(q_raw)

    week_src = sources["week"]
    week_sheet = detect_week_sheet(week_src)
    week_src = rewind_file(week_src)
    week_df = pd.read_excel(week_src, sheet_name=week_sheet)
    staff, shifts, week_dates = standardize_staff_and_shifts(week_df, break_threshold, break_hours)
    staff = merge_staff_qualifications(staff, quals)

    hak_raw = read_excel_sheet(sources["hakedis"])
    hakedis = standardize_hakedis(hak_raw)
    flights = enrich_flights_with_requirements(flights, hakedis)
    return flights, quals, staff, shifts, hakedis, week_dates, week_sheet, ""

