def make_excel_report(sheets: Dict[str, pd.DataFrame]) -> bytes:
    output = BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter", datetime_format="dd.mm.yyyy hh:mm", date_format="dd.mm.yyyy") as writer:
        for sheet_name, df in sheets.items():
            if df is None:
                continue
            data = df.copy()
            for c in list(data.columns):
                if str(c).startswith("_") or c == "staff_id":
                    data = data.drop(columns=[c])
            data.to_excel(writer, sheet_name=sheet_name[:31], index=False)
            ws = writer.sheets[sheet_name[:31]]
            wb = writer.book
            header_fmt = wb.add_format({"bold": True, "bg_color": "#F26722", "font_color": "white", "border": 1})
            for col_num, value in enumerate(data.columns):
                ws.write(0, col_num, value, header_fmt)
                width = min(max(len(str(value)) + 2, 12), 38)
                ws.set_column(col_num, col_num, width)
            ws.freeze_panes(1, 0)
    return output.getvalue()


def make_pdf_summary(flights: pd.DataFrame, staff: pd.DataFrame, plan: pd.DataFrame, warnings: pd.DataFrame, service_warn: pd.DataFrame, rest_warn: pd.DataFrame) -> bytes:
    """Basit yönetici PDF özeti oluşturur. Detaylı tablo için Excel raporu ana çıktı olarak kullanılır."""
    from reportlab.lib import colors
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.lib.styles import getSampleStyleSheet
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle

    buffer = BytesIO()
    doc = SimpleDocTemplate(buffer, pagesize=landscape(A4), rightMargin=24, leftMargin=24, topMargin=24, bottomMargin=24)
    styles = getSampleStyleSheet()
    story = []
    story.append(Paragraph("Çelebi YHM - Haftalık Planlama Özeti", styles["Title"]))
    story.append(Paragraph(f"Oluşturma zamanı: {datetime.now():%d.%m.%Y %H:%M}", styles["Normal"]))
    story.append(Spacer(1, 12))

    active_staff = int(staff.get("active", pd.Series(dtype=bool)).sum()) if not staff.empty and "active" in staff.columns else len(staff)
    total_hakedis = int(flights.get("manual_required_total", pd.Series(dtype=float)).fillna(0).sum()) if not flights.empty else 0
    assigned = len(plan) if plan is not None else 0
    coverage = f"{(assigned / total_hakedis * 100):.1f}%" if total_hakedis else "0%"
    metrics = [
        ["Aktif Personel", str(active_staff), "Toplam Uçuş", str(len(flights))],
        ["Toplam Hakediş", str(total_hakedis), "Atanan Görev", str(assigned)],
        ["Plan Doluluk", coverage, "Plan Uyarısı", str(len(warnings) if warnings is not None else 0)],
        ["Servis Uyarısı", str(len(service_warn) if service_warn is not None else 0), "11 Saat İhlali", str(len(rest_warn) if rest_warn is not None else 0)],
    ]
    tbl = Table(metrics, colWidths=[120, 90, 120, 90])
    tbl.setStyle(TableStyle([
        ("BACKGROUND", (0,0), (-1,0), colors.HexColor("#F26722")),
        ("TEXTCOLOR", (0,0), (-1,0), colors.white),
        ("GRID", (0,0), (-1,-1), 0.5, colors.grey),
        ("FONTNAME", (0,0), (-1,-1), "Helvetica-Bold"),
        ("ALIGN", (1,0), (1,-1), "CENTER"),
        ("ALIGN", (3,0), (3,-1), "CENTER"),
    ]))
    story.append(tbl)
    story.append(Spacer(1, 14))

    if plan is not None and not plan.empty:
        show_cols = [c for c in ["Uçuş ID", "STD", "Personel", "Görev Rolü", "Güzergah", "Vardiya"] if c in plan.columns]
        sample = plan[show_cols].head(28).copy()
        for c in sample.columns:
            sample[c] = sample[c].astype(str).str.slice(0, 36)
        data = [sample.columns.tolist()] + sample.values.tolist()
        pt = Table(data, repeatRows=1)
        pt.setStyle(TableStyle([
            ("BACKGROUND", (0,0), (-1,0), colors.HexColor("#333333")),
            ("TEXTCOLOR", (0,0), (-1,0), colors.white),
            ("GRID", (0,0), (-1,-1), 0.25, colors.lightgrey),
            ("FONTSIZE", (0,0), (-1,-1), 7),
        ]))
        story.append(Paragraph("Plan önizleme - ilk 28 satır", styles["Heading2"]))
        story.append(pt)
    else:
        story.append(Paragraph("Henüz plan oluşturulmadı.", styles["Heading2"]))

    doc.build(story)
    return buffer.getvalue()

