def get_embedded_asset(name: str) -> str:
    return EMBEDDED_ASSETS.get(name, "")


def file_to_data_uri(file_obj, fallback_asset: str = "celebi_logo") -> str:
    """Return a data URI for an uploaded Streamlit file, falling back to embedded asset."""
    if file_obj is None:
        return get_embedded_asset(fallback_asset)
    try:
        rewind_file(file_obj)
        data = file_obj.read()
        rewind_file(file_obj)
        if not data:
            return get_embedded_asset(fallback_asset)
        name = getattr(file_obj, "name", "logo.png").lower()
        mime = "image/jpeg" if name.endswith((".jpg", ".jpeg")) else "image/png"
        return f"data:{mime};base64,{base64.b64encode(data).decode('ascii')}"
    except Exception:
        return get_embedded_asset(fallback_asset)


def render_flying_background():
    plane_order = [
        ("plane_lufthansa", "plane-one"),
        ("plane_saudi", "plane-two"),
        ("plane_uzbekistan", "plane-three"),
        ("plane_etihad", "plane-four"),
        ("plane_emirates", "plane-five"),
    ]
    html = '<div class="sky-layer" aria-hidden="true">'
    for key, cls in plane_order:
        html += f'<img class="flying-plane {cls}" src="{get_embedded_asset(key)}" />'
    html += '</div>'
    st.markdown(html, unsafe_allow_html=True)


