def _secret_value(key: str, default: str) -> str:
    try:
        return str(st.secrets.get(key, default))
    except Exception:
        return default


def allowed_user_ids() -> List[str]:
    raw = _secret_value("AUTH_USER_IDS", ",".join(DEFAULT_AUTHORIZED_USER_IDS))
    ids = [normalize_text(x) for x in re.split(r"[,;|\n]+", raw) if normalize_text(x)]
    return ids or DEFAULT_AUTHORIZED_USER_IDS


