def init_state(staff: pd.DataFrame, week_dates: List[pd.Timestamp], force=False):
    if force or "staff_editor_v2" not in st.session_state:
        st.session_state.staff_editor_v2 = staff[["name", "email", "work_type", "gender", "route", "base_role", "role_override", "active", "flight_qualifications"]].copy()
    if force or "request_editor_v2" not in st.session_state:
        default_date = week_dates[0].date() if week_dates else date.today()
        first = staff["name"].iloc[0] if not staff.empty else ""
        st.session_state.request_editor_v2 = pd.DataFrame([{"Personel": first, "Tarih": default_date, "Tip": "DO Talebi", "Not": ""}])
    if "manual_plan_v2" not in st.session_state:
        st.session_state.manual_plan_v2 = pd.DataFrame()
    if "alias_editor_v2" not in st.session_state:
        st.session_state.alias_editor_v2 = pd.DataFrame([{"A/L Kodu": k, "Qualification Aliasları": ", ".join(v)} for k, v in DEFAULT_AIRLINE_ALIASES.items()])


def main():
    st.set_page_config(page_title=APP_TITLE, page_icon="✈️", layout="wide")
    inject_css()
    login_gate()

    if "current_page_v4" not in st.session_state:
        st.session_state.current_page_v4 = "Ana Sayfa"

    with st.sidebar:
        st.subheader("Navigasyon")
        nav_choice = st.radio("Sayfa", ["Ana Sayfa", "Planlama"], index=0 if st.session_state.current_page_v4 == "Ana Sayfa" else 1, label_visibility="collapsed")
        if nav_choice != st.session_state.current_page_v4:
            st.session_state.current_page_v4 = nav_choice
            st.rerun()
        st.divider()
        st.subheader("Logo ve Dosyalar")
        logo = st.file_uploader("Çelebi logosu yükle", type=["png", "jpg", "jpeg"])
        upload_departure = st.file_uploader("DEPARTURE dosyası", type=["csv", "xlsx"])
        upload_qual = st.file_uploader("QUALIFICATIONLAR-YHM dosyası", type=["csv", "xlsx"])
        upload_week = st.file_uploader("20. HAFTA YHM / vardiya dosyası", type=["xlsx"])
        upload_hakedis = st.file_uploader("Hakediş dosyası", type=["xlsx"])
