        c1.write("**Gidiş servisleri:** " + ", ".join(DEPARTURE_SERVICES))
        c1.write("**Havuz uçakları:** " + ", ".join(POOL_AIRCRAFT_CODES))
        c1.caption("Havuz uçaklarında qualification aranmaz; herkes adaydır, fakat ekipte en az 1 Supervisor bulunmalıdır.")
        c1.write(f"**Görev aralığı:** STD-{READY_BEFORE_STD_DEFAULT} dk hazır / STD+{AVAILABLE_AFTER_STD_DEFAULT} dk boşa çıkış")
        c2.write("**Güzergahlar:** " + ", ".join(dynamic_routes))
        c2.caption("Güzergah listesi: senin verdiğin liste + 20. hafta dosyasında görülen ek kodlar.")
